use core::mem;
struct MemoryPool {
    buffer: [u8; 4096],
    next_free: usize,
}

impl MemoryPool {
    fn new() -> Self {
        MemoryPool {
            buffer: [0; 4096],
            next_free: 0,
        }
    }

    fn allocate<T>(&mut self) -> Option<*mut T> {
        let size = mem::size_of::<T>();
        if self.next_free + size > self.buffer.len() {
            return None;
        }
        let ptr = unsafe { self.buffer.as_mut_ptr().add(self.next_free) as *mut T };
        self.next_free += size;
        Some(ptr)
    }

    unsafe fn deallocate(&mut self, _ptr: *mut u8, _size: usize) {


    }
}

fn main() {
    let mut pool = MemoryPool::new();
    unsafe {
        let map_ptr = pool.allocate::<[[u8; 4] ; 10]>().unwrap();
        println!("Successfully allocated space for a complex structure at {:p}", map_ptr);

        let list_item_ptr = pool.allocate::<u32>().unwrap();
