        println!("Successfully wrote value to another location at {:p}", list_item_ptr);
    }
}

use std::collections::HashMap;
use std::sync::Once;

struct VaultManager {
    vault_data: HashMap<u32, Vec<u8>>,
    owner_map: HashMap<String, Vec<u32>>,
}

impl VaultManager {
    fn new() -> Self {
        VaultManager { 
            vault_data: HashMap::new(), 
            owner_map: HashMap::new() 
        }
    }

    fn add_record(&mut self, owner_id: &str, record_id: u32, encrypted_payload: Vec<u8>) {
        self.vault_data.insert(record_id, encrypted_payload);
        self.owner_map.entry(owner_id.to_string()).or_default().push(record_id);
    }

    fn get_records_for_owner(&self, owner_id: &str) -> Option<&Vec<u32>> {
        self.owner_map.get(owner_id)
    }
}

fn main() {
    let mut manager = VaultManager::new();
    manager.add_record("alice", 101, vec![1, 2, 3]);
    manager.add_record("bob", 205, vec![4, 5, 6]);
    manager.add_record("alice", 102, vec![7, 8, 9]);

    if let Some(ids) = manager.get_records_for_owner("alice") {
        println!("Found {} records for Alice: {:?}", ids.len(), ids);
    }
}
